
/**
 * @Component
 */
class AppComponent {
  /**
   * @Qualifier("UserComponent")
   */
  userComponent;

  run() {
    // Debug print before accessing nested properties
    console.log('DEBUG: AppComponent.run() userComponent:', this.userComponent);
    if (this.userComponent) {
      console.log('DEBUG: AppComponent.run() userComponent.userService:', this.userComponent.userService);
      if (this.userComponent.userService) {
        console.log('DEBUG: AppComponent.run() userComponent.userService.db:', this.userComponent.userService.db);
      } else {
        console.log('DEBUG: AppComponent.run() userComponent.userService is undefined');
      }
    } else {
      console.log('DEBUG: AppComponent.run() userComponent is undefined');
    }
    // userComponent und darunter userService.db müssen jetzt existieren
    this.userComponent.userService.db.initialize();
    this.userComponent.run();
  }
}

module.exports = AppComponent;
